package servlets;
import db.DBConnection; import javax.servlet.*; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*; import java.sql.*; import java.util.*;
@WebServlet("/people") public class SkillSearchServlet extends HttpServlet { protected void doGet(HttpServletRequest req,HttpServletResponse resp)throws ServletException,IOException{String skill=req.getParameter("skill");if(skill==null)skill="";List<Map<String,Object>> people=new ArrayList<>();List<String> skills=new ArrayList<>();try(Connection c=DBConnection.getConnection()){
 try(PreparedStatement p=c.prepareStatement("SELECT Name FROM Skills ORDER BY Name");ResultSet r=p.executeQuery()){while(r.next())skills.add(r.getString(1));}
 String q="SELECT u.User_ID,u.First_Name,u.Last_Name,s.Major,s.Grad_Year,s.Bio,GROUP_CONCAT(sk.Name ORDER BY sk.Name SEPARATOR ', ') Skill_List FROM Users u JOIN Students s ON s.User_ID=u.User_ID LEFT JOIN HasSkill hs ON hs.User_ID=u.User_ID LEFT JOIN Skills sk ON sk.Skill_ID=hs.Skill_ID WHERE u.Is_Active=1 "+(skill.isBlank()?"":"AND EXISTS(SELECT 1 FROM HasSkill hx JOIN Skills sx ON sx.Skill_ID=hx.Skill_ID WHERE hx.User_ID=u.User_ID AND sx.Name=?) ")+"GROUP BY u.User_ID,u.First_Name,u.Last_Name,s.Major,s.Grad_Year,s.Bio ORDER BY u.First_Name,u.Last_Name";
 try(PreparedStatement p=c.prepareStatement(q)){if(!skill.isBlank())p.setString(1,skill);try(ResultSet r=p.executeQuery()){while(r.next()){Map<String,Object>m=new HashMap<>();for(String k:new String[]{"User_ID","First_Name","Last_Name","Major","Grad_Year","Bio","Skill_List"})m.put(k,r.getObject(k));people.add(m);}}}
 }catch(SQLException e){throw new ServletException(e);}req.setAttribute("skillOptions",skills);req.setAttribute("people",people);req.setAttribute("selectedSkill",skill);req.getRequestDispatcher("people.jsp").forward(req,resp);}}
